const payload = $json.body ?? $json;

const objeto = String(payload.objeto ?? payload.object ?? '').trim().toLowerCase();
const confianza = Number(payload.confianza ?? payload.confidence ?? 0);
const camara = String(payload.camara ?? payload.camera ?? 'unknown');
const hora = String(payload.hora ?? new Date().toISOString());
const box = payload.box ?? null;
const imagen = payload.imagen ?? payload.image_path ?? null;

const reglas = {
  alto: new Set(['knife', 'gun', 'scissors']),
  medio: new Set(['person', 'car', 'truck', 'backpack', 'cell phone'])
};

let riesgo = 'BAJO';
let accion = 'MONITOREAR';
let prioridad = 2;
let motivo = 'Objeto sin regla de amenaza alta.';

if (!objeto) {
  riesgo = 'DESCONOCIDO';
  accion = 'REVISAR_PAYLOAD';
  prioridad = 1;
  motivo = 'No se recibio el campo objeto.';
} else if (reglas.alto.has(objeto) && confianza >= 0.6) {
  riesgo = 'ALTO';
  accion = 'ENVIAR_ALERTA';
  prioridad = 10;
  motivo = `Objeto peligroso detectado: ${objeto}.`;
} else if (reglas.medio.has(objeto) && confianza >= 0.5) {
  riesgo = 'MEDIO';
  accion = 'REGISTRAR_Y_MONITOREAR';
  prioridad = 5;
  motivo = `Objeto relevante detectado: ${objeto}.`;
} else if (confianza < 0.5) {
  riesgo = 'BAJO';
  accion = 'IGNORAR_BAJA_CONFIANZA';
  prioridad = 1;
  motivo = `Confianza baja: ${confianza}.`;
}

return [
  {
    json: {
      status: 'procesado',
      agente: 'AgenteAnalisis',
      version: '0.1.0',
      entrada: {
        objeto,
        confianza,
        camara,
        hora,
        box,
        imagen
      },
      resultado: {
        riesgo,
        accion,
        prioridad,
        motivo
      },
      procesado_en: new Date().toISOString()
    }
  }
];
